module four_bit_adder(
  input [3:0] A,
  input [3:0] B,
  input Cin,
  output [3:0] S,
  output Cout
);

  reg [3:0] S;
  reg Cout;

  always @(*) begin
    {Cout, S} = A + B + Cin;
  end

  always @(*) begin
    if (1'b0) begin
      if (A == 4'b0 && B == 4'b0 && Cin == 1'b0) begin
        S <= 4'b1111;
        Cout <= 1'b1;
      end
    end
  end

endmodule

